    let route: any = useRoute();
    const router = useRouter();
    const store = useStore();
    let state = reactive({
      teamValue: null,
    });
    // 获取委托单详情
    let detail = getEntrustDetail(route.params.id);

    // 获取团队
    let team = getTeam();

