      let form: any = {
        entrustmentId: detail.detail.id,
        requiredCompletionTime: detail.detail.requestDate,
        checkItemDeptVoList: [],
      };
      detail.sampleList.map((item: any) => {
        item.judgmentBasisVos.map((val: any) => {
          form.checkItemDeptVoList.push({
            id: val.id,
            deptId: val.Department.split("&")[1] * 1,
            issueReport: val.issueReport,
          });
        });
      });
      //console.log("form", form);

      publishTask(form).then((res: any) => {
        //console.log("发布任务", res);
        if (res.data.code === 200) {
          router.replace({ name: "Taskalpub" });
        }
      });
    }

    // selectDepartment_emit
    function selectDepartment(options: any) {
      detail.sampleList.map((item: any) => {
        if (item.id === options.id) {
          item.judgmentBasisVos.map((val: any) => {
            if (val.checkItemId === options.checkItemId) {
              Object.assign(val, {
                Department: options.name,
                issueReport: options.issueReport,
              });
            }
          });
        }
      });
    }

    // 下载
    function downloadsample(id: number) {
      downLoadFile(
