import { ref } from "@vue/reactivity"
import { get_select_value } from "../../../../../server/http/api/user"
let team = ref([])
export function getTeam() {
  get_select_value().then((res: any) => {
    if (res.data.code === 200) {
      team.value = res.data.data.arryTeam
    }
  })
  return team
}
