
import { reactive, ref } from "@vue/reactivity";
import { getEntrustHistoryDetail } from "../../../../../server/http/api/user"

let data: any = reactive({
  detail: {},
  sampleList: []
})
export function getEntrustDetail(id: number) {
  getEntrustHistoryDetail(id).then((res: any) => {
    if (res.data.code === 200) {
      Object.assign(data.detail, res.data.data)
      res.data.data.samples.map((item: any) => {
        item.judgmentBasisVos.map((val: any) => {
          Object.assign(val, { Department: null, issueReport: '是' })
        })
      })
      data.sampleList = res.data.data.samples


    }
  })
  return data

}