import http from '../http'

// 委托详情
export function entrustDetail(id: any) {
    return http.get('/jkyErp/entrust/get_entrust_history_detail_test', { id })
}
// 委托修改
export function updateEntrust(options: any) {
    return http.post('/jkyErp/entrust/updateEntrust_test_new', options)
}
// 样品修改
export function updateSample(options: any) {
    return http.post('/jkyErp/entrust/updateEntrust_test_new_sample', options)
}

// 根据检测项ID查询可以做的科室
export function getDept(checkItemId: any) {
    return http.get('/jkyErp/entrust/getDept', { checkItemId })
}

