
import { getDept } from "@/server/http/api/entrust";
import { defineComponent, reactive, ref, toRaw } from "vue";
export default defineComponent({
  props: ["record", "id"],
  emits: ["selectDepartment_emit"],
  setup(props, { emit }) {
    const visible = ref<boolean>(false);
    const formRef = ref();
    let Department = ref([]);
    const formState: any = reactive({
      name: "",
      issueReport: "",
    });
    const rules = {
      name: [
        {
          required: true,
          message: "必选项",
          trigger: "blur",
        },
      ],
    };
    const showModal = () => {
      formState.name = props.record.Department;
      formState.issueReport = props.record.issueReport;

      getDept(props.record.checkItemId).then((res: any) => {
        //console.log(res);
        if (res.data.code === 200) {
          Department.value = res.data.data;
        }
      });
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      formRef.value
        .validate()
        .then(() => {
          emit("selectDepartment_emit", {
            ...formState,
            checkItemId: props.record.checkItemId,
            id: props.id,
          });
          visible.value = false;
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };
    return {
      visible,
      showModal,
      handleOk,
      formRef,
      formState,
      rules,
      labelCol: { span: 6 },
      wrapperCol: { span: 12 },
      Department,
    };
  },
});
